class Solution:
    def xorBeauty(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        # Key insight: for each bit position, count how many triplets have 1 at that bit
        # The result is 1 at that position if count is odd

        result = 0

        for bit in range(30):  # 32-bit integer
            count = 0
            for i in nums:
                for j in nums:
                    for k in nums:
                        # Check if ((i|j) & k) has bit set
                        if (((i | j) & k) >> bit) & 1:
                            count += 1

            # If count is odd, this bit contributes to XOR result
            if count % 2 == 1:
                result |= (1 << bit)

        return result
